import{_ as a,o as e,c as l,ae as o}from"./chunks/framework.Co1PSFSm.js";const b=JSON.parse('{"title":"ChatDev 2.0 Web UI 快速入门指南","description":"","frontmatter":{},"headers":[],"relativePath":"zh/web-ui.md","filePath":"zh/web-ui.md"}'),r={name:"zh/web-ui.md"};function i(n,t,d,h,s,c){return e(),l("div",null,[...t[0]||(t[0]=[o('<h1 id="chatdev-2-0-web-ui-快速入门指南" tabindex="-1">ChatDev 2.0 Web UI 快速入门指南 <a class="header-anchor" href="#chatdev-2-0-web-ui-快速入门指南" aria-label="Permalink to &quot;ChatDev 2.0 Web UI 快速入门指南&quot;">​</a></h1><p>本指南帮助用户快速上手 ChatDev 2.0 Web UI，涵盖主要功能页面和操作流程。</p><h2 id="_1-系统入口" tabindex="-1">1. 系统入口 <a class="header-anchor" href="#_1-系统入口" aria-label="Permalink to &quot;1. 系统入口&quot;">​</a></h2><p>启动前后端服务后，访问 <code>http://localhost:5173</code> 进入 Web UI。</p><h2 id="_2-主要页面" tabindex="-1">2. 主要页面 <a class="header-anchor" href="#_2-主要页面" aria-label="Permalink to &quot;2. 主要页面&quot;">​</a></h2><h3 id="_2-1-首页-home" tabindex="-1">2.1 首页 (Home) <a class="header-anchor" href="#_2-1-首页-home" aria-label="Permalink to &quot;2.1 首页 (Home)&quot;">​</a></h3><p>系统首页，提供快速导航入口。</p><h3 id="_2-2-工作流列表-workflow-list" tabindex="-1">2.2 工作流列表 (Workflow List) <a class="header-anchor" href="#_2-2-工作流列表-workflow-list" aria-label="Permalink to &quot;2.2 工作流列表 (Workflow List)&quot;">​</a></h3><p>查看和管理所有可用的工作流 YAML 文件。</p><p><strong>功能</strong>：</p><ul><li>浏览 <code>yaml_instance/</code> 目录下的工作流</li><li>预览 YAML 配置内容</li><li>选择工作流进入执行或编辑</li></ul><h3 id="_2-3-启动页-launch-view" tabindex="-1">2.3 启动页 (Launch View) <a class="header-anchor" href="#_2-3-启动页-launch-view" aria-label="Permalink to &quot;2.3 启动页 (Launch View)&quot;">​</a></h3><p>工作流执行的主界面，是最常用的页面。</p><p><strong>操作流程</strong>：</p><ol><li><strong>选择工作流</strong>：从左侧列表选择要执行的 YAML 文件</li><li><strong>上传附件</strong>（可选）：点击上传按钮添加文件（如 CSV 数据、图片等）</li><li><strong>输入任务提示</strong>：在文本框中输入指导工作流执行的提示词</li><li><strong>点击 Launch</strong>：启动工作流执行</li></ol><p><strong>执行期间</strong>：</p><ul><li><strong>节点视图</strong>：观察节点状态变化（pending → running → success/failed）</li><li><strong>输出面板</strong>：实时查看执行日志、节点输出上下文和生成的工件（三者共用同一面板）</li></ul><p><strong>人工输入</strong>：</p><ul><li>当执行到 <code>human</code> 节点时，界面会显示输入提示</li><li>填写文本内容或上传附件后提交继续执行</li></ul><h3 id="_2-4-工作流工作台-workflow-workbench" tabindex="-1">2.4 工作流工作台 (Workflow Workbench) <a class="header-anchor" href="#_2-4-工作流工作台-workflow-workbench" aria-label="Permalink to &quot;2.4 工作流工作台 (Workflow Workbench)&quot;">​</a></h3><p>可视化工作流编辑器。</p><p><strong>功能</strong>：</p><ul><li>拖拽式节点编辑</li><li>节点配置面板</li><li>边连接与条件设置</li><li>导出为 YAML 文件</li></ul><h3 id="_2-5-教程页-tutorial" tabindex="-1">2.5 教程页 (Tutorial) <a class="header-anchor" href="#_2-5-教程页-tutorial" aria-label="Permalink to &quot;2.5 教程页 (Tutorial)&quot;">​</a></h3><p>内置教程，帮助新用户了解系统功能。</p><h2 id="_3-常用操作" tabindex="-1">3. 常用操作 <a class="header-anchor" href="#_3-常用操作" aria-label="Permalink to &quot;3. 常用操作&quot;">​</a></h2><h3 id="_3-1-运行工作流" tabindex="-1">3.1 运行工作流 <a class="header-anchor" href="#_3-1-运行工作流" aria-label="Permalink to &quot;3.1 运行工作流&quot;">​</a></h3><ol><li>进入 <strong>Launch View</strong></li><li>从左侧选择工作流</li><li>输入 Task Prompt（任务提示）</li><li>点击 <strong>Launch</strong> 按钮</li><li>观察执行过程，等待完成</li></ol><h3 id="_3-2-上传附件" tabindex="-1">3.2 上传附件 <a class="header-anchor" href="#_3-2-上传附件" aria-label="Permalink to &quot;3.2 上传附件&quot;">​</a></h3><ol><li>在 Launch View 中点击上传按钮</li><li>选择文件（支持 CSV 数据、图片等格式）</li><li>附件将作为上下文传递给工作流节点</li></ol><h3 id="_3-3-查看日志" tabindex="-1">3.3 查看日志 <a class="header-anchor" href="#_3-3-查看日志" aria-label="Permalink to &quot;3.3 查看日志&quot;">​</a></h3><ol><li>工作流执行过程中，切换到 <strong>输出面板</strong></li><li>查看实时执行日志</li><li>可查看节点输出上下文和生成的工件</li></ol><h3 id="_3-4-人工审阅节点交互" tabindex="-1">3.4 人工审阅节点交互 <a class="header-anchor" href="#_3-4-人工审阅节点交互" aria-label="Permalink to &quot;3.4 人工审阅节点交互&quot;">​</a></h3><p>当工作流包含 <code>human</code> 节点时：</p><ol><li>执行暂停并显示提示信息</li><li>阅读上下文内容</li><li>输入审阅意见或操作指令</li><li>点击提交继续执行</li></ol><h2 id="_4-快捷键" tabindex="-1">4. 快捷键 <a class="header-anchor" href="#_4-快捷键" aria-label="Permalink to &quot;4. 快捷键&quot;">​</a></h2><table tabindex="0"><thead><tr><th>快捷键</th><th>功能</th></tr></thead><tbody><tr><td><code>Ctrl/Cmd + Enter</code></td><td>提交输入</td></tr><tr><td><code>Esc</code></td><td>关闭弹窗/面板</td></tr></tbody></table><h2 id="_5-故障排查" tabindex="-1">5. 故障排查 <a class="header-anchor" href="#_5-故障排查" aria-label="Permalink to &quot;5. 故障排查&quot;">​</a></h2><table tabindex="0"><thead><tr><th>问题</th><th>解决方案</th></tr></thead><tbody><tr><td>页面无法加载</td><td>确认前端服务 <code>npm run dev</code> 正常运行</td></tr><tr><td>无法连接后端</td><td>确认后端服务 <code>uv run python server_main.py</code> 正常运行</td></tr><tr><td>工作流列表为空</td><td>检查 <code>yaml_instance/</code> 目录是否有 YAML 文件</td></tr><tr><td>执行无响应</td><td>检查浏览器开发者工具的 Network/Console 日志</td></tr><tr><td>WebSocket 断开</td><td>刷新页面重新建立连接</td></tr></tbody></table>',39)])])}const _=a(r,[["render",i]]);export{b as __pageData,_ as default};
